"""Tests for the file upload service."""
import os
import pytest
from unittest.mock import patch, MagicMock
from services.upload import (
    sanitize_filename,
    validate_file_type,
    validate_file_size,
    generate_storage_path,
    handle_upload,
    InvalidFileTypeError,
    FileSizeExceededError,
    FileUploadError,
)


class TestSanitizeFilename:
    def test_simple_filename(self):
        assert sanitize_filename("report.pdf") == "report.pdf"

    def test_strips_path_traversal(self):
        assert ".." not in sanitize_filename("../etc/passwd")

    def test_strips_backslash_traversal(self):
        assert ".." not in sanitize_filename("..\\windows\\system32\\config")

    def test_strips_leading_slashes(self):
        result = sanitize_filename("/etc/passwd")
        assert not result.startswith("/")

    def test_replaces_spaces(self):
        assert " " not in sanitize_filename("my report final.pdf")

    def test_empty_filename_raises(self):
        with pytest.raises(FileUploadError):
            sanitize_filename("")

    def test_preserves_extension(self):
        result = sanitize_filename("My Document (1).docx")
        assert result.endswith(".docx")


class TestValidateFileType:
    def test_accepts_pdf(self):
        assert validate_file_type("report.pdf") is True

    def test_accepts_docx(self):
        assert validate_file_type("notes.docx") is True

    def test_accepts_png(self):
        assert validate_file_type("screenshot.png") is True

    def test_accepts_jpg(self):
        assert validate_file_type("photo.jpg") is True

    def test_rejects_exe(self):
        with pytest.raises(InvalidFileTypeError):
            validate_file_type("malware.exe")

    def test_rejects_sh(self):
        with pytest.raises(InvalidFileTypeError):
            validate_file_type("script.sh")

    def test_case_insensitive(self):
        assert validate_file_type("IMAGE.PNG") is True


class TestValidateFileSize:
    def test_accepts_small_file(self):
        data = b"x" * 1024  # 1KB
        assert validate_file_size(data) is True

    def test_accepts_at_limit(self):
        data = b"x" * (25 * 1024 * 1024)  # exactly 25MB
        assert validate_file_size(data) is True

    def test_rejects_oversized(self):
        data = b"x" * (25 * 1024 * 1024 + 1)
        with pytest.raises(FileSizeExceededError):
            validate_file_size(data)


class TestGenerateStoragePath:
    def test_returns_string(self):
        path = generate_storage_path("report.pdf")
        assert isinstance(path, str)

    def test_includes_uploads_prefix(self):
        path = generate_storage_path("report.pdf")
        assert path.startswith("uploads/")

    def test_preserves_extension(self):
        path = generate_storage_path("report.pdf")
        assert path.endswith(".pdf")

    def test_unique_paths(self):
        path1 = generate_storage_path("report.pdf")
        path2 = generate_storage_path("report.pdf")
        assert path1 != path2


class TestHandleUpload:
    @patch("services.upload.save_to_disk")
    def test_successful_upload(self, mock_save):
        mock_save.return_value = "/srv/docuflow/data/uploads/abc123.pdf"
        result = handle_upload("report.pdf", b"%PDF-1.4 fake content")
        assert "path" in result
        mock_save.assert_called_once()

    @patch("services.upload.save_to_disk")
    def test_rejects_invalid_type(self, mock_save):
        with pytest.raises(InvalidFileTypeError):
            handle_upload("virus.exe", b"malicious")
        mock_save.assert_not_called()

    @patch("services.upload.save_to_disk")
    def test_rejects_oversized(self, mock_save):
        data = b"x" * (26 * 1024 * 1024)
        with pytest.raises(FileSizeExceededError):
            handle_upload("big.pdf", data)
        mock_save.assert_not_called()

